          <div className="relative z-10 max-w-2xl mx-auto">
            <h2 className="text-4xl md:text-5xl font-bold mb-6">Stay on top of your lectures.</h2>
            <p className="text-lg md:text-xl text-white/90 mb-10">
              Join 500+ students waiting for the smartest way to manage their university schedule.
            </p>

            {submitted ? (
              <div className="bg-white/20 backdrop-blur-md p-6 rounded-2xl animate-pulse">
                <p className="text-xl font-bold">You're on the list! 🎉</p>
                <p className="text-sm opacity-90 mt-1">We'll notify you as soon as we launch.</p>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-4">
                <input 
                  type="email" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
